async function completeTask(taskId, options = {}, cwd2 = process.cwd()) {
  if (!isInitialized(cwd2)) {
    console.error("Error: Project not initialized. Please run `projmnt4claude setup` first");
    process.exit(1);
  }
  const task = readTaskMeta(taskId, cwd2);
  if (!task) {
    console.error(`Error: Task '${taskId}' does not exist`);
    process.exit(1);
  }
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log(`\uD83D\uDE80 One-click complete task: ${taskId}`);
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log("");
  const taskDir = path11.join(getTasksDir(cwd2), taskId);
  const checkpointPath = path11.join(taskDir, "checkpoint.md");
  if (fs15.existsSync(checkpointPath)) {
    const content = fs15.readFileSync(checkpointPath, "utf-8");
    const lines = content.split(`
`).filter((line) => line.trim().startsWith("- ["));
    if (lines.length > 0) {
      const unchecked = lines.filter((line) => !line.includes("[x]") && !line.includes("[X]"));
      if (unchecked.length > 0) {
        console.log("⚠️  Found incomplete checkpoints:");
        unchecked.forEach((line, idx) => {
          const text = line.replace(/- \[[xX ]\] /, "").trim();
          console.log(`   ${idx + 1}. ${text}`);
        });
        console.log("");
        if (!options.yes) {
          const response = await import_prompts2.default({
            type: "confirm",
            name: "proceed",
            message: "是否标记所有Checkpoints为Completed并继续?",
            initial: false
          });
          if (!response.proceed) {
            console.log("Cancelled. Please complete checkpoints before trying again.");
            return;
          }
        }
        let newContent = content;
        for (const line of unchecked) {
          newContent = newContent.replace(line, line.replace("[ ]", "[x]"));
        }
        fs15.writeFileSync(checkpointPath, newContent, "utf-8");
        console.log("✅ All checkpoints auto-marked as completed");
      }
    }
  }
  task.status = "resolved";
  writeTaskMeta(task, cwd2);
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log(`\uD83C\uDF89 Task ${taskId} Completed！`);
  console.log("");
  console.log(`   Title: ${task.title}`);
  console.log(`   Status: ✅ Resolved`);
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  if (!options.yes) {
    console.log("");
    console.log("\uD83D\uDCA1 Tip: Recommend adding completion notes to record solution and experience");
    console.log("");
    const addNote = await import_prompts2.default({
      type: "confirm",
      name: "confirm",
      message: "是否添加完成Description?",
      initial: true
    });
    if (addNote.confirm) {
      const noteResponse = await import_prompts2.default({
        type: "text",
        name: "note",
        message: "请输入完成Description（解决方案, 关键决策等）:",
        validate: (value) => value.trim().length > 0 ? true : "Description不能为空"
      });
      if (noteResponse.note) {
        if (!task.history) {
          task.history = [];
        }
        task.history.push({
          timestamp: new Date().toISOString(),
          action: "添加完成Description",
          field: "completionNote",
          newValue: noteResponse.note
        });
        const taskDir2 = path11.join(getTasksDir(cwd2), taskId);
        const notesDir = path11.join(taskDir2, "notes");
        if (!fs15.existsSync(notesDir)) {
          fs15.mkdirSync(notesDir, { recursive: true });
        }
        const notePath = path11.join(notesDir, `completion-${new Date().toISOString().slice(0, 10)}.md`);
        fs15.writeFileSync(notePath, `# 完成Description

${noteResponse.note}
`, "utf-8");
        writeTaskMeta(task, cwd2);
        console.log("");
        console.log("✅ Completion note saved");
      }
    }
  }
}
