async function completeCheckpoint(taskId, options = {}, cwd2 = process.cwd()) {
  if (!isInitialized(cwd2)) {
    console.error("Error: Project not initialized. Please run `projmnt4claude setup` first");
    process.exit(1);
  }
  const task = readTaskMeta(taskId, cwd2);
  if (!task) {
    console.error(`Error: Task '${taskId}' does not exist`);
    process.exit(1);
  }
  const taskDir = path11.join(getTasksDir(cwd2), taskId);
  const checkpointPath = path11.join(taskDir, "checkpoint.md");
  if (!fs15.existsSync(checkpointPath)) {
    console.log("No checkpoint file");
    return;
  }
  const content = fs15.readFileSync(checkpointPath, "utf-8");
  const lines = content.split(`
`).filter((line) => line.trim().startsWith("- ["));
  if (lines.length === 0) {
    console.log("No checkpoint items found in file");
    return;
  }
  console.log("");
  console.log("\uD83D\uDCCB Checkpoint Confirmation");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log("");
  let allPassed = true;
  const updatedLines = [];
  for (const line of lines) {
    const isChecked = line.includes("[x]") || line.includes("[X]");
    const checkText = line.replace(/- \[[xX ]\] /, "").trim();
    if (!isChecked) {
      if (options.yes) {
        updatedLines.push(line.replace("[ ]", "[x]"));
        console.log(`   ✅ ${checkText} (auto-confirmed)`);
      } else {
        const response = await import_prompts2.default({
          type: "confirm",
          name: "passed",
          message: `Checkpoints: ${checkText}`,
          initial: false
        });
        if (response.passed) {
          updatedLines.push(line.replace("[ ]", "[x]"));
          console.log(`   ✅ passed`);
        } else {
          updatedLines.push(line);
          allPassed = false;
          console.log(`   ❌ failed`);
        }
      }
    } else {
      updatedLines.push(line);
    }
  }
  let newContent = content;
  for (let i = 0;i < lines.length; i++) {
    newContent = newContent.replace(lines[i], updatedLines[i]);
  }
  fs15.writeFileSync(checkpointPath, newContent, "utf-8");
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  if (allPassed) {
    console.log("\uD83C\uDF89 All checkpoints passed!");
    console.log("");
    console.log("Recommend running the following command to complete task:");
    console.log(`   projmnt4claude task update ${taskId} --status resolved`);
    if (options.yes) {
      task.status = "resolved";
      writeTaskMeta(task, cwd2);
      console.log(`✅ Task ${taskId} auto-marked as resolved`);
    } else {
      const response = await import_prompts2.default({
        type: "confirm",
        name: "complete",
        message: "是否立即将Task标记为Resolved?",
        initial: true
      });
      if (response.complete) {
        task.status = "resolved";
        writeTaskMeta(task, cwd2);
        console.log(`✅ Task ${taskId} marked as resolved`);
      }
    }
  } else {
    console.log("⚠️ Some checkpoints failed, please continue working");
  }
}
