// src/utils/log-analyzer.ts
init_path();
init_logger();
import * as fs24 from "fs";
import * as path20 from "path";

class LogCollector {
  cwd;
  logger;
  constructor(cwd2 = process.cwd()) {
    this.cwd = cwd2;
    this.logger = new Logger({ component: "log-collector", cwd: cwd2 });
  }
  collect(options = {}) {
    const {
      maxFiles = 10,
      maxEntries = 5000,
      startDate,
      endDate,
      minLevel,
      commands
    } = options;
    const logsDir = getLogsDir(this.cwd);
    if (!fs24.existsSync(logsDir)) {
      return [];
    }
    const logFiles = fs24.readdirSync(logsDir).filter((f) => f.endsWith(".log")).sort().reverse().slice(0, maxFiles);
    const allEntries = [];
    const levelPriority = {
      error: 0,
      warn: 1,
      info: 2,
      debug: 3
    };
    for (const file of logFiles) {
      const filePath = path20.join(logsDir, file);
      try {
        const content = fs24.readFileSync(filePath, "utf-8");
        const lines = content.split(`
`).filter((l) => l.trim());
        for (const line of lines) {
          try {
            const entry = JSON.parse(line);
            if (startDate && entry.timestamp < startDate)
              continue;
            if (endDate && entry.timestamp > endDate)
              continue;
            if (minLevel && levelPriority[entry.level] > levelPriority[minLevel])
              continue;
            if (commands && commands.length > 0) {
              const fileCmd = file.replace(/-\d{8}\.log$/, "");
              if (!commands.includes(fileCmd))
                continue;
            }
            allEntries.push(entry);
          } catch {}
        }
      } catch {}
    }
    return allEntries.slice(0, maxEntries);
  }
  collectSince(hours, options = {}) {
    const startDate = new Date(Date.now() - hours * 3600 * 1000).toISOString();
    return this.collect({ ...options, startDate });
  }
  getStats() {
    const logsDir = getLogsDir(this.cwd);
    if (!fs24.existsSync(logsDir)) {
      return { fileCount: 0, totalSizeKB: 0, oldestFile: null, newestFile: null };
    }
    const files = fs24.readdirSync(logsDir).filter((f) => f.endsWith(".log"));
    let totalSizeKB = 0;
    for (const f of files) {
      try {
        const stat = fs24.statSync(path20.join(logsDir, f));
        totalSizeKB += stat.size / 1024;
      } catch {}
    }
    const sorted = files.sort();
    return {
      fileCount: files.length,
      totalSizeKB: Math.round(totalSizeKB),
      oldestFile: sorted[0] || null,
      newestFile: sorted[sorted.length - 1] || null
    };
  }
}

class LogAnalyzerRegistry {
  analyzers = new Map;
  logger;
  constructor(cwd2 = process.cwd()) {
    this.logger = new Logger({ component: "log-analyzer-registry", cwd: cwd2 });
  }
  register(analyzer) {
    if (this.analyzers.has(analyzer.name)) {
      this.logger.warn(`分析器 '${analyzer.name}' 已存在，将被覆盖`);
    }
    this.analyzers.set(analyzer.name, analyzer);
    return this;
  }
  unregister(name) {
    return this.analyzers.delete(name);
  }
  get(name) {
    return this.analyzers.get(name);
  }
  getAll() {
    return [...this.analyzers.values()];
  }
  getByCategory(category) {
    return this.getAll().filter((a) => a.category === category);
  }
  getByStrategy(strategy) {
    return this.getAll().filter((a) => a.supportedStrategies.includes(strategy));
  }
  async runAll(entries, strategy = "rule", context) {
    const results = [];
    const applicableAnalyzers = this.getByStrategy(strategy);
    for (const analyzer of applicableAnalyzers) {
      try {
        const result = await analyzer.analyze(entries, strategy, context);
        results.push(result);
      } catch (err) {
        this.logger.warn(`分析器 '${analyzer.name}' 执行失败: ${err instanceof Error ? err.message : String(err)}`);
      }
    }
    return results;
  }
  get size() {
    return this.analyzers.size;
  }
}

class AnalysisReporter {
  buildReport(results, filesScanned, totalEntries) {
    const allFindings = results.flatMap((r) => r.findings);
    const bySeverity = {};
    const byCategory = {};
    for (const f of allFindings) {
      bySeverity[f.severity] = (bySeverity[f.severity] || 0) + 1;
      byCategory[f.category] = (byCategory[f.category] || 0) + 1;
    }
    return {
      generatedAt: new Date().toISOString(),
      filesScanned,
      totalEntries,
      results,
      summary: {
        totalFindings: allFindings.length,
        bySeverity,
        byCategory
      }
    };
  }
  formatText(report) {
    const lines = [];
    lines.push(`\uD83D\uDCCA 日志分析报告`);
    lines.push(`生成时间: ${report.generatedAt}`);
    lines.push(`扫描文件: ${report.filesScanned} 个 | 日志条目: ${report.totalEntries} 条`);
    lines.push("");
    if (report.summary.totalFindings === 0) {
      lines.push("✅ 未发现异常");
      return lines.join(`
`);
    }
    lines.push("## 汇总");
    const sevIcons = {
      critical: "\uD83D\uDD34",
      error: "❌",
      warning: "⚠️",
      info: "ℹ️"
    };
    for (const [sev, count] of Object.entries(report.summary.bySeverity)) {
      lines.push(`  ${sevIcons[sev] || "•"} ${sev}: ${count}`);
    }
    lines.push("");
    for (const result of report.results) {
      if (result.findings.length === 0)
        continue;
      lines.push(`## ${result.analyzerName} (${result.strategy})`);
      lines.push(`  扫描: ${result.stats.entriesScanned} 条 | 发现: ${result.stats.findingsCount} 个问题 | 耗时: ${result.stats.durationMs}ms`);
      lines.push("");
      for (const finding of result.findings) {
        lines.push(`  ${sevIcons[finding.severity]} [${finding.severity.toUpperCase()}] ${finding.title}`);
        lines.push(`    ${finding.description}`);
        if (finding.recommendation) {
          lines.push(`    \uD83D\uDCA1 建议: ${finding.recommendation}`);
        }
        if (finding.evidence.length > 0 && finding.evidence.length <= 3) {
          lines.push(`    证据: ${finding.evidence.join(", ")}`);
        } else if (finding.evidence.length > 3) {
          lines.push(`    证据: ${finding.evidence.slice(0, 3).join(", ")} ... (+${finding.evidence.length - 3})`);
        }
        lines.push("");
      }
    }
    return lines.join(`
`);
  }
  formatJSON(report) {
    return JSON.stringify(report, null, 2);
  }
}

// src/utils/log-analyzers/headless-claude-analyzer.ts
class HeadlessClaudeAnalyzer {
  name = "headless-claude-analyzer";
  category = "headless-claude";
  supportedStrategies = ["rule", "hybrid"];
  async analyze(entries, strategy, _context) {
    const startTime = Date.now();
    const findings = [];
    const aiEntries = entries.filter((e) => e.component?.includes("headless") || e.component?.includes("claude-code") || e.component?.includes("feedback-constraint") || e.message && (e.message.includes("Claude Code") || e.message.includes("invoke") || e.message.includes("AI 调用")));
    const failedInvokes = aiEntries.filter((e) => e.level === "error" && (e.message.includes("失败") || e.message.includes("failed") || e.message.includes("error")));
    if (failedInvokes.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "error",
        category: this.category,
        title: `检测到 ${failedInvokes.length} 次 AI 调用失败`,
        description: "短时间内多次 AI 调用失败可能表示 API 配置错误、网络问题或服务不可用",
        evidence: failedInvokes.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查 API key 配置、网络连接，或查看 AI provider 服务状态",
        detectedAt: new Date().toISOString()
      });
    } else if (failedInvokes.length >= 1) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${failedInvokes.length} 次 AI 调用失败`,
        description: "存在少量 AI 调用失败",
        evidence: failedInvokes.map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "关注失败频率，如果持续增加建议排查",
        detectedAt: new Date().toISOString()
      });
    }
    const jsonErrors = aiEntries.filter((e) => e.level === "error" && (e.message.includes("JSON") || e.message.includes("解析失败") || e.message.includes("parse")));
    if (jsonErrors.length >= 2) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${jsonErrors.length} 次输出格式错误`,
        description: "AI 输出不符合预期 JSON 格式，FeedbackConstraintEngine 需要多次重试",
        evidence: jsonErrors.slice(0, 3).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "考虑调整 prompt 约束或降低输出复杂度",
        detectedAt: new Date().toISOString()
      });
    }
    const timeouts = aiEntries.filter((e) => e.message.includes("超时") || e.message.includes("timeout") || e.message.includes("ETIMEDOUT"));
    if (timeouts.length >= 2) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${timeouts.length} 次 AI 调用超时`,
        description: "频繁超时可能影响流水线执行效率",
        evidence: timeouts.slice(0, 3).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "考虑增加超时时间或优化 prompt 长度",
        detectedAt: new Date().toISOString()
      });
    }
    const retryEntries = aiEntries.filter((e) => e.message.includes("重试") || e.message.includes("retry") || e.message.includes("Retrying"));
    if (retryEntries.length >= 5) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${retryEntries.length} 次重试`,
        description: "大量重试可能表明系统性问题或 prompt 需要优化",
        evidence: retryEntries.slice(0, 3).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查重试原因，优化 prompt 或调整 maxRetries 配置",
        detectedAt: new Date().toISOString()
      });
    }
    return {
      analyzerName: this.name,
      strategy: strategy === "hybrid" ? "hybrid" : "rule",
      findings,
      stats: {
        entriesScanned: aiEntries.length,
        findingsCount: findings.length,
        durationMs: Date.now() - startTime
      }
    };
  }
}
// src/utils/log-analyzers/harness-pipeline-analyzer.ts
class HarnessPipelineAnalyzer {
  name = "harness-pipeline-analyzer";
  category = "harness-pipeline";
  supportedStrategies = ["rule", "ai", "hybrid"];
  async analyze(entries, strategy, _context) {
    const startTime = Date.now();
    const findings = [];
    const pipelineEntries = entries.filter((e) => e.component?.includes("harness") || e.component?.includes("assembly-line") || e.component?.includes("pipeline") || e.message && (e.message.includes("批次") || e.message.includes("阶段") || e.message.includes("流水线") || e.message.includes("assembly") || e.message.includes("phase")));
    const stuckEntries = pipelineEntries.filter((e) => e.level === "error" && (e.message.includes("超时") || e.message.includes("timeout") || e.message.includes("stuck")));
    if (stuckEntries.length >= 2) {
      findings.push({
        analyzer: this.name,
        severity: "error",
        category: this.category,
        title: `检测到 ${stuckEntries.length} 个任务可能卡住`,
        description: "多个任务出现超时，可能导致流水线整体阻塞",
        evidence: stuckEntries.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查被阻塞任务的具体原因，考虑增加超时时间或拆分复杂任务",
        detectedAt: new Date().toISOString()
      });
    }
    const transitionErrors = pipelineEntries.filter((e) => e.level === "error" && (e.message.includes("阶段转换") || e.message.includes("transition") || e.message.includes("NOPASS")));
    if (transitionErrors.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${transitionErrors.length} 次阶段转换失败`,
        description: "频繁的阶段转换失败可能表示代码质量系统性问题",
        evidence: transitionErrors.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查失败任务的评估反馈，关注共性问题",
        detectedAt: new Date().toISOString()
      });
    }
    const batchFailures = pipelineEntries.filter((e) => e.level === "error" && (e.message.includes("批次") && (e.message.includes("失败") || e.message.includes("failed"))));
    if (batchFailures.length >= 2) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${batchFailures.length} 个批次执行失败`,
        description: "批次级别的失败会影响整个流水线进度",
        evidence: batchFailures.map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查失败批次中的具体任务，修复后重新执行",
        detectedAt: new Date().toISOString()
      });
    }
    const gateFailures = pipelineEntries.filter((e) => e.message.includes("质量门禁") || e.message.includes("quality gate") || e.message.includes("quality-gate"));
    const failedGates = gateFailures.filter((e) => e.message.includes("失败") || e.message.includes("未通过") || e.message.includes("NOPASS"));
    if (failedGates.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${failedGates.length} 次质量门禁未通过`,
        description: "质量门禁频繁失败，任务内容可能需要改进",
        evidence: failedGates.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查质量评分较低的维度，针对性提升任务描述质量",
        detectedAt: new Date().toISOString()
      });
    }
    return {
      analyzerName: this.name,
      strategy: strategy === "ai" ? "ai" : "rule",
      findings,
      stats: {
        entriesScanned: pipelineEntries.length,
        findingsCount: findings.length,
        durationMs: Date.now() - startTime
      }
    };
  }
}
// src/utils/log-analyzers/api-error-analyzer.ts
class APIErrorAnalyzer {
  name = "api-error-analyzer";
  category = "api-error";
  supportedStrategies = ["rule", "ai", "hybrid"];
  async analyze(entries, strategy, _context) {
    const startTime = Date.now();
    const findings = [];
    const apiEntries = entries.filter((e) => e.level === "error" || e.level === "warn" || e.message && (e.message.includes("API") || e.message.includes("429") || e.message.includes("500") || e.message.includes("token") || e.message.includes("rate limit") || e.message.includes("permission")));
    const rateLimits = apiEntries.filter((e) => e.message.includes("429") || e.message.includes("rate limit") || e.message.includes("Rate limit"));
    if (rateLimits.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "error",
        category: this.category,
        title: `检测到 ${rateLimits.length} 次 API 速率限制 (429)`,
        description: "频繁触发速率限制会影响任务执行效率",
        evidence: rateLimits.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "降低并发数、增加重试延迟，或联系 API provider 提升配额",
        detectedAt: new Date().toISOString()
      });
    } else if (rateLimits.length >= 1) {
      findings.push({
        analyzer: this.name,
        severity: "info",
        category: this.category,
        title: `检测到 ${rateLimits.length} 次 API 速率限制`,
        description: "少量速率限制属于正常情况",
        evidence: rateLimits.map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "无需处理，持续关注频率即可",
        detectedAt: new Date().toISOString()
      });
    }
    const serverErrors = apiEntries.filter((e) => e.message.includes("500") || e.message.includes("502") || e.message.includes("503"));
    if (serverErrors.length >= 2) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${serverErrors.length} 次 API 服务端错误`,
        description: "服务端错误可能表示 API provider 存在稳定性问题",
        evidence: serverErrors.slice(0, 3).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "配置适当的重试策略，关注 API provider 状态页面",
        detectedAt: new Date().toISOString()
      });
    }
    const authErrors = apiEntries.filter((e) => e.message.includes("permission") || e.message.includes("auth") || e.message.includes("401") || e.message.includes("403"));
    if (authErrors.length >= 1) {
      findings.push({
        analyzer: this.name,
        severity: "critical",
        category: this.category,
        title: `检测到 ${authErrors.length} 次权限/认证错误`,
        description: "权限错误会阻止所有 API 调用，需要立即修复",
        evidence: authErrors.map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查 API key 是否有效、权限配置是否正确",
        detectedAt: new Date().toISOString()
      });
    }
    const tokenEntries = entries.filter((e) => e.data && typeof e.data === "object" && (("totalTokens" in e.data) || ("tokensUsed" in e.data)));
    if (tokenEntries.length > 0) {
      const tokenValues = tokenEntries.map((e) => {
        const d = e.data;
        return Number(d.totalTokens || d.tokensUsed || 0);
      }).filter((v) => v > 0);
      if (tokenValues.length > 0) {
        const avgTokens = tokenValues.reduce((a, b) => a + b, 0) / tokenValues.length;
        const maxTokens = Math.max(...tokenValues);
        if (maxTokens > 50000) {
          findings.push({
            analyzer: this.name,
            severity: "warning",
            category: this.category,
            title: `检测到单次调用消耗 ${maxTokens} tokens`,
            description: `平均消耗: ${Math.round(avgTokens)} tokens，最大消耗: ${maxTokens} tokens`,
            evidence: [`平均: ${Math.round(avgTokens)} tokens`, `最大: ${maxTokens} tokens`, `调用次数: ${tokenValues.length}`],
            recommendation: "优化 prompt 长度，避免在单次调用中传递过多上下文",
            detectedAt: new Date().toISOString()
          });
        }
      }
    }
    return {
      analyzerName: this.name,
      strategy: strategy === "ai" ? "ai" : "rule",
      findings,
      stats: {
        entriesScanned: apiEntries.length,
        findingsCount: findings.length,
        durationMs: Date.now() - startTime
      }
    };
  }
}
// src/utils/log-analyzers/performance-analyzer.ts
class PerformanceAnalyzer {
  name = "performance-analyzer";
  category = "performance";
  supportedStrategies = ["rule", "hybrid"];
  SLOW_THRESHOLD_MS = 60000;
  VERY_SLOW_THRESHOLD_MS = 300000;
  async analyze(entries, strategy, _context) {
    const startTime = Date.now();
    const findings = [];
    const perfEntries = entries.filter((e) => e.data && typeof e.data === "object" && ("durationMs" in e.data));
    const timeoutEntries = entries.filter((e) => e.message.includes("超时") || e.message.includes("timeout") || e.message.includes("timed out"));
    const slowOps = perfEntries.filter((e) => {
      const duration = Number(e.data?.durationMs || 0);
      return duration > this.SLOW_THRESHOLD_MS;
    });
    const verySlowOps = slowOps.filter((e) => {
      const duration = Number(e.data?.durationMs || 0);
      return duration > this.VERY_SLOW_THRESHOLD_MS;
    });
    if (verySlowOps.length >= 1) {
      findings.push({
        analyzer: this.name,
        severity: "error",
        category: this.category,
        title: `检测到 ${verySlowOps.length} 个极慢操作 (>5min)`,
        description: "超过5分钟的操作严重影响效率",
        evidence: verySlowOps.slice(0, 3).map((e) => {
          const duration = Number(e.data?.durationMs || 0);
          return `[${e.timestamp}] ${e.message} (${(duration / 1000).toFixed(1)}s)`;
        }),
        recommendation: "拆分复杂任务、优化 prompt 长度或增加超时配置",
        detectedAt: new Date().toISOString()
      });
    } else if (slowOps.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${slowOps.length} 个慢操作 (>1min)`,
        description: "多个操作超过1分钟，可能影响流水线整体效率",
        evidence: slowOps.slice(0, 3).map((e) => {
          const duration = Number(e.data?.durationMs || 0);
          return `[${e.timestamp}] ${e.message} (${(duration / 1000).toFixed(1)}s)`;
        }),
        recommendation: "关注耗时最长的操作，考虑优化或拆分",
        detectedAt: new Date().toISOString()
      });
    }
    if (timeoutEntries.length >= 3) {
      findings.push({
        analyzer: this.name,
        severity: "warning",
        category: this.category,
        title: `检测到 ${timeoutEntries.length} 次超时`,
        description: "频繁超时可能表示任务复杂度过高或资源配置不足",
        evidence: timeoutEntries.slice(0, 5).map((e) => `[${e.timestamp}] ${e.message}`),
        recommendation: "检查超时配置，适当增加 timeout 或降低任务复杂度",
        detectedAt: new Date().toISOString()
      });
    }
    const errorEntries = entries.filter((e) => e.level === "error");
    const totalEntries = entries.length;
    if (totalEntries > 10) {
      const errorRate = errorEntries.length / totalEntries;
      if (errorRate > 0.2) {
        findings.push({
          analyzer: this.name,
          severity: "error",
          category: this.category,
          title: `错误率过高: ${(errorRate * 100).toFixed(1)}% (${errorEntries.length}/${totalEntries})`,
          description: "超过20%的日志条目为错误级别",
          evidence: [`总条目: ${totalEntries}`, `错误条目: ${errorEntries.length}`],
          recommendation: "排查主要错误来源，优先解决高频错误",
          detectedAt: new Date().toISOString()
        });
      } else if (errorRate > 0.1) {
        findings.push({
          analyzer: this.name,
          severity: "warning",
          category: this.category,
          title: `错误率偏高: ${(errorRate * 100).toFixed(1)}%`,
          description: "超过10%的日志条目为错误级别",
          evidence: [`总条目: ${totalEntries}`, `错误条目: ${errorEntries.length}`],
          recommendation: "关注错误趋势",
          detectedAt: new Date().toISOString()
        });
      }
    }
    const messageCounts = {};
    for (const e of entries) {
      const key = e.message.slice(0, 80);
      messageCounts[key] = (messageCounts[key] || 0) + 1;
    }
    const highFreqMessages = Object.entries(messageCounts).filter(([, count]) => count > 50).sort((a, b) => b[1] - a[1]).slice(0, 3);
    if (highFreqMessages.length > 0) {
      findings.push({
        analyzer: this.name,
        severity: "info",
        category: this.category,
        title: "检测到高频操作模式",
        description: "某些操作在短时间内被大量执行",
        evidence: highFreqMessages.map(([msg, count]) => `"${msg}...": ${count} 次`),
        recommendation: "检查是否存在不必要的重复操作或循环",
        detectedAt: new Date().toISOString()
      });
    }
    return {
      analyzerName: this.name,
      strategy: strategy === "hybrid" ? "hybrid" : "rule",
      findings,
      stats: {
        entriesScanned: entries.length,
        findingsCount: findings.length,
        durationMs: Date.now() - startTime
      }
    };
  }
}
// src/utils/log-analyzers/index.ts
function getBuiltInAnalyzers() {
  return [
    new HeadlessClaudeAnalyzer,
    new HarnessPipelineAnalyzer,
    new APIErrorAnalyzer,
    new PerformanceAnalyzer
  ];
}

