function checkPluginCache(cwd2) {
  const texts = t(cwd2).doctorCmd;
  const pluginRoot = process.env.CLAUDE_PLUGIN_ROOT;
  const details = [];
  let status = "ok";
  let message = texts.checkPluginCacheNormal;
  if (!pluginRoot) {
    return {
      name: texts.checkPluginCache,
      status: "ok",
      message: texts.checkPluginCacheCliMode,
      details: ["CLAUDE_PLUGIN_ROOT not set (normal in CLI mode)"],
      fixable: false
    };
  }
  details.push(`Plugin root: ${pluginRoot}`);
  const mainFile = path21.join(pluginRoot, "dist", "projmnt4claude.js");
  if (!fs25.existsSync(mainFile)) {
    status = "error";
    message = texts.checkPluginCacheMainFileMissing;
    details.push(`Missing: ${mainFile}`);
  } else {
    details.push(`✓ Main program: ${mainFile}`);
  }
  const localesDir = path21.join(pluginRoot, "locales");
  if (!fs25.existsSync(localesDir)) {
    if (status !== "error") {
      status = "warning";
      message = texts.checkPluginCacheLocalesMissing;
    }
    details.push(`Missing: ${localesDir}`);
  } else {
    const zhDir = path21.join(localesDir, "zh");
    const enDir = path21.join(localesDir, "en");
    if (fs25.existsSync(zhDir)) {
      details.push("✓ Chinese language pack: locales/zh/");
    }
    if (fs25.existsSync(enDir)) {
      details.push("✓ English language pack: locales/en/");
    }
    if (!fs25.existsSync(zhDir) && !fs25.existsSync(enDir)) {
      if (status !== "error") {
        status = "warning";
        message = "Language pack directories missing";
      }
      details.push("Warning: No language pack directories found");
    }
  }
  const commandsDir = path21.join(pluginRoot, "commands");
  if (!fs25.existsSync(commandsDir)) {
    if (status !== "error") {
      status = "warning";
      message = texts.checkPluginCacheCommandsMissing;
    }
    details.push(`Missing: ${commandsDir}`);
  } else {
    const commandFiles = fs25.readdirSync(commandsDir).filter((f) => f.endsWith(".md"));
    details.push(`✓ Slash commands: ${commandFiles.length}`);
  }
  return {
    name: texts.checkPluginCache,
    status,
    message,
    details,
    fixable: false
  };
}
