var DEPRECATED_HOOK_SCRIPTS = ["pre-complete.ts", "post-task.ts", "pre-task.ts", "plan-complete.ts", "config.json"];
function checkDeprecatedHooks(cwd2) {
  const results = [];
  const deprecatedSettings = [];
  const deprecatedFiles = [];
  const settingsPath = path21.join(cwd2, ".claude", "settings.json");
  if (fs25.existsSync(settingsPath)) {
    try {
      const settings = JSON.parse(fs25.readFileSync(settingsPath, "utf-8"));
      const hooks = settings.hooks || {};
      for (const [hookType, hookConfig] of Object.entries(hooks)) {
        if (typeof hookConfig === "string") {
          if (hookConfig.includes("projmnt4claude/hooks/")) {
            deprecatedSettings.push(`${hookType}: ${hookConfig}`);
          }
        } else if (Array.isArray(hookConfig)) {
          for (const item of hookConfig) {
            if (typeof item === "string" && item.includes("projmnt4claude/hooks/")) {
              deprecatedSettings.push(`${hookType}[]: ${item}`);
            } else if (typeof item === "object" && item !== null) {
              const hookItem = item;
              const hookValue = hookItem.command || hookItem.script || hookItem.run || "";
              if (hookValue.includes("projmnt4claude/hooks/")) {
                deprecatedSettings.push(`${hookType}: ${hookValue}`);
              }
            }
          }
        } else if (typeof hookConfig === "object" && hookConfig !== null) {
          const hookObj = hookConfig;
          const hookValue = hookObj.command || hookObj.script || hookObj.run || "";
          if (hookValue.includes("projmnt4claude/hooks/")) {
            deprecatedSettings.push(`${hookType}: ${hookValue}`);
          }
        }
      }
    } catch {}
  }
  const hooksDir = path21.join(cwd2, ".projmnt4claude", "hooks");
  if (fs25.existsSync(hooksDir)) {
    try {
      const files = fs25.readdirSync(hooksDir);
      for (const file of files) {
        if (DEPRECATED_HOOK_SCRIPTS.includes(file)) {
          deprecatedFiles.push(file);
        }
      }
    } catch {}
  }
  const texts = t(cwd2).doctorCmd;
  const hasSettingsIssue = deprecatedSettings.length > 0;
  const hasFilesIssue = deprecatedFiles.length > 0;
  if (hasSettingsIssue || hasFilesIssue) {
    const details = ["Deprecated Claude Code Hook config found, run doctor --fix to clean"];
    if (hasSettingsIssue) {
      details.push("");
      details.push("Deprecated hooks in .claude/settings.json:");
      for (const setting of deprecatedSettings) {
        details.push(`  - ${setting}`);
      }
    }
    if (hasFilesIssue) {
      details.push("");
      details.push(`Deprecated scripts in .projmnt4claude/hooks/:`);
      for (const file of deprecatedFiles) {
        details.push(`  - ${file}`);
      }
    }
    details.push("");
    details.push("⚠️  Deprecation notice:");
    details.push("  Claude Code Hook feature has been removed, residual config may cause issues");
    details.push("");
    details.push("\uD83D\uDCA1 Run projmnt4claude doctor --fix to auto-clean");
    results.push({
      name: texts.checkDeprecatedHooks,
      status: "warning",
      message: texts.checkDeprecatedHooksFound,
      details,
      fixable: true
    });
  } else {
    results.push({
      name: texts.checkDeprecatedHooks,
      status: "ok",
      message: texts.checkDeprecatedHooksOk,
      details: [],
      fixable: false
    });
  }
  return results;
}
function displayResults(results, cwd2 = process.cwd()) {
  const texts = t(cwd2).doctorCmd;
  const sorted = [...results].sort((a, b) => {
    const order = { error: 0, warning: 1, ok: 2 };
    return order[a.status] - order[b.status];
  });
  let errorCount = 0;
  let warningCount = 0;
  let okCount = 0;
  for (const result of sorted) {
    const icon = result.status === "ok" ? "✅" : result.status === "warning" ? "⚠️" : "❌";
    console.log(`${icon} ${result.name}: ${result.message}`);
    if (result.details && result.details.length > 0) {
      for (const detail of result.details) {
        console.log(`   ${detail}`);
      }
    }
    if (result.status === "error")
      errorCount++;
    else if (result.status === "warning")
      warningCount++;
    else
      okCount++;
  }
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log("\uD83D\uDCCA " + texts.summary.replace("{errors}", String(errorCount)).replace("{warnings}", String(warningCount)).replace("{ok}", String(okCount)));
  if (errorCount === 0 && warningCount === 0) {
    console.log("✅ " + texts.allChecksPassed);
  }
}
function resolvePluginRoot() {
  if (process.env.CLAUDE_PLUGIN_ROOT) {
    return process.env.CLAUDE_PLUGIN_ROOT;
  }
  try {
    let dir = __dirname;
    for (let i = 0;i < 3; i++) {
      if (fs25.existsSync(path21.join(dir, "locales"))) {
        return dir;
      }
      dir = path21.dirname(dir);
    }
  } catch {}
  return null;
}
async function fixIssues3(issues, cwd2) {
  const texts = t(cwd2).doctorCmd;
  const projectDir = getProjectDir(cwd2);
  const pluginRoot = resolvePluginRoot();
  for (const issue of issues) {
    console.log(texts.fixing.replace("{name}", issue.name));
    if (issue.name === "Skill Files" || issue.name === "Command Docs") {
      if (pluginRoot) {
        const toolboxDir = getToolboxDir(cwd2);
        const skillDir = path21.join(toolboxDir, "projmnt4claude");
        if (!fs25.existsSync(skillDir)) {
          fs25.mkdirSync(skillDir, { recursive: true });
        }
        const configPath = path21.join(projectDir, "config.json");
        let language = "zh";
        if (fs25.existsSync(configPath)) {
          try {
            const config = JSON.parse(fs25.readFileSync(configPath, "utf-8"));
            language = config.language || "zh";
          } catch {}
        }
        const skillSource = path21.join(pluginRoot, "locales", language, "SKILL.md");
        const skillTarget = path21.join(skillDir, "SKILL.md");
        if (fs25.existsSync(skillSource)) {
          fs25.copyFileSync(skillSource, skillTarget);
          console.log(texts.copiedSkillMd);
        }
        const commandsSourceDir = path21.join(pluginRoot, "locales", language, "commands");
        const commandsTargetDir = path21.join(skillDir, "commands");
        if (fs25.existsSync(commandsSourceDir)) {
          if (!fs25.existsSync(commandsTargetDir)) {
            fs25.mkdirSync(commandsTargetDir, { recursive: true });
          }
          const commandFiles = fs25.readdirSync(commandsSourceDir).filter((f) => f.endsWith(".md"));
          for (const file of commandFiles) {
            fs25.copyFileSync(path21.join(commandsSourceDir, file), path21.join(commandsTargetDir, file));
          }
          console.log(texts.copiedCommandDocs.replace("{count}", String(commandFiles.length)));
        }
      } else {
        console.log(texts.cannotFixPluginRootNotFound);
      }
    } else if (issue.name.startsWith("Directory:")) {
      const dirName = issue.name.replace("Directory: ", "");
      const dirMap = {
        tasks: getTasksDir(cwd2),
        toolbox: getToolboxDir(cwd2),
        archive: path21.join(projectDir, "archive")
      };
      const dirPath = dirMap[dirName];
      if (dirPath && !fs25.existsSync(dirPath)) {
        fs25.mkdirSync(dirPath, { recursive: true });
        console.log(texts.createdDirectory.replace("{name}", dirName));
      }
    } else if (issue.name === texts.checkLogDirectory) {
      const logsDir = getLogsDir(cwd2);
      if (!fs25.existsSync(logsDir)) {
        fs25.mkdirSync(logsDir, { recursive: true });
        console.log(texts.createdLogsDirectory);
      }
    } else if (issue.name === texts.checkLogConfigCompleteness || issue.name === texts.checkAiConfigCompleteness || issue.name === texts.checkTrainingConfigCompleteness) {
      const config = readConfig(cwd2);
      if (config) {
        const fixedConfig = ensureConfigDefaults(config);
        writeConfig(fixedConfig, cwd2);
        console.log(texts.autoFilledMissingConfig);
      }
    } else if (issue.name === texts.checkDeprecatedStatus) {
      const tasksDir = getTasksDir(cwd2);
      const deprecatedMap = { reopened: "open", needs_human: "open" };
      let fixedCount = 0;
      for (const taskId of getAllTaskIds(cwd2)) {
        const metaPath = path21.join(tasksDir, taskId, "meta.json");
        if (fs25.existsSync(metaPath)) {
          try {
            const meta = JSON.parse(fs25.readFileSync(metaPath, "utf-8"));
            if (deprecatedMap[meta.status]) {
              const oldStatus = meta.status;
              meta.status = deprecatedMap[oldStatus];
              if (!meta.transitionNotes)
                meta.transitionNotes = [];
              meta.transitionNotes.push({
                timestamp: new Date().toISOString(),
                fromStatus: oldStatus,
                toStatus: meta.status,
                note: `doctor --fix: ${oldStatus} status deprecated (v4), migrated to ${meta.status}`,
                author: "doctor-fix"
              });
              meta.updatedAt = new Date().toISOString();
              fs25.writeFileSync(metaPath, JSON.stringify(meta, null, 2), "utf-8");
              fixedCount++;
            }
          } catch {}
        }
      }
      console.log(texts.migratedDeprecatedStatusTasks.replace("{count}", String(fixedCount)));
    } else if (issue.name === texts.checkDeprecatedHooks) {
      let removedSettings = false;
      let removedFiles = false;
      const settingsPath = path21.join(cwd2, ".claude", "settings.json");
      if (fs25.existsSync(settingsPath)) {
        try {
          const settings = JSON.parse(fs25.readFileSync(settingsPath, "utf-8"));
          const hooks = settings.hooks || {};
          let modified = false;
          for (const [hookType, hookConfig] of Object.entries(hooks)) {
            let shouldRemove = false;
            if (typeof hookConfig === "string") {
              if (hookConfig.includes("projmnt4claude/hooks/")) {
                shouldRemove = true;
              }
            } else if (Array.isArray(hookConfig)) {
              const filtered = hookConfig.filter((item) => {
                if (typeof item === "string") {
                  return !item.includes("projmnt4claude/hooks/");
                } else if (typeof item === "object" && item !== null) {
                  const hookItem = item;
                  const hookValue = hookItem.command || hookItem.script || hookItem.run || "";
                  return !hookValue.includes("projmnt4claude/hooks/");
                }
                return true;
              });
              if (filtered.length !== hookConfig.length) {
                if (filtered.length === 0) {
                  shouldRemove = true;
                } else {
                  hooks[hookType] = filtered;
                  modified = true;
                }
              }
            } else if (typeof hookConfig === "object" && hookConfig !== null) {
              const hookObj = hookConfig;
              const hookValue = hookObj.command || hookObj.script || hookObj.run || "";
              if (hookValue.includes("projmnt4claude/hooks/")) {
                shouldRemove = true;
              }
            }
            if (shouldRemove) {
              delete hooks[hookType];
              modified = true;
            }
          }
          if (modified) {
            fs25.writeFileSync(settingsPath, JSON.stringify(settings, null, 2), "utf-8");
            removedSettings = true;
          }
        } catch {}
      }
      const hooksDir = path21.join(cwd2, ".projmnt4claude", "hooks");
      if (fs25.existsSync(hooksDir)) {
        try {
          const files = fs25.readdirSync(hooksDir);
          for (const file of files) {
            if (DEPRECATED_HOOK_SCRIPTS.includes(file)) {
              const filePath = path21.join(hooksDir, file);
              fs25.unlinkSync(filePath);
              removedFiles = true;
            }
          }
          const remainingFiles = fs25.readdirSync(hooksDir);
          if (remainingFiles.length === 0) {
            fs25.rmdirSync(hooksDir);
          }
        } catch {}
      }
      if (removedSettings || removedFiles) {
        console.log(texts.cleanedDeprecatedHookConfig);
        if (removedSettings) {
          console.log(texts.updatedSettings);
        }
        if (removedFiles) {
          console.log(texts.deletedDeprecatedScripts);
        }
      }
    }
  }
  console.log("");
  console.log("✅ " + texts.fixComplete);
}
