async function loadTaskQueue(options, cwd2) {
  if (options.plan) {
    const planFile = path28.resolve(cwd2, options.plan);
    if (!fs32.existsSync(planFile)) {
      console.error(`Error: Plan file does not exist: ${planFile}`);
      process.exit(1);
    }
    try {
      const planContent = fs32.readFileSync(planFile, "utf-8");
      const planData = JSON.parse(planContent);
      let taskQueue = planData.recommendation?.suggestedOrder || [];
      const batches = planData.batchOrder || planData.batches;
      if (taskQueue.length === 0) {
        console.error("Error: No tasks in plan file");
        process.exit(1);
      }
      const TERMINAL_STATUSES_SET6 = new Set(TERMINAL_STATUSES);
      const originalCount = taskQueue.length;
      taskQueue = taskQueue.filter((id) => {
        const task = readTaskMeta(id, cwd2);
        if (!task)
          return false;
        return !TERMINAL_STATUSES_SET6.has(normalizeStatus(task.status));
      });
      if (originalCount - taskQueue.length > 0) {
        console.log(`Using plan file: ${options.plan} (filtered ${originalCount - taskQueue.length} terminal tasks)`);
      } else {
        console.log(`Using plan file: ${options.plan}`);
      }
      return buildBatchAwareQueue(taskQueue, batches);
    } catch (error) {
      console.error(`Error: Cannot parse plan file: ${planFile}`);
      console.error(error instanceof Error ? error.message : String(error));
      process.exit(1);
    }
  }
  const executionPlan = readPlan(cwd2);
  if (executionPlan && executionPlan.tasks.length > 0) {
    const queue = filterExecutableFromPlan(executionPlan, cwd2, "\uD83D\uDCCB Using project execution plan");
    if (queue.taskQueue.length > 0) {
      return queue;
    }
    console.log("⚠️  All tasks in execution plan are in terminal state");
  }
  console.log("\uD83D\uDD0D No execution plan found, auto-generating...");
  try {
    await recommendPlan2({ nonInteractive: true, json: false }, cwd2);
    const newPlan = readPlan(cwd2);
    if (newPlan && newPlan.tasks.length > 0) {
      const queue = filterExecutableFromPlan(newPlan, cwd2, "✅ Execution plan auto-generated");
      if (queue.taskQueue.length > 0) {
        return queue;
      }
    }
  } catch (error) {
    console.error("Warning: Auto-generate plan failed:", error instanceof Error ? error.message : String(error));
  }
  console.error("Error: Cannot get task list");
  console.error("Hint: Please run `projmnt4claude plan recommend` to generate execution plan");
  process.exit(1);
}
function filterExecutableFromPlan(plan, cwd2, logPrefix) {
  const TERMINAL_STATUSES_SET6 = new Set(TERMINAL_STATUSES);
  const filteredTasks = plan.tasks.filter((taskId) => {
    const task = readTaskMeta(taskId, cwd2);
    if (!task)
      return false;
    return !TERMINAL_STATUSES_SET6.has(normalizeStatus(task.status));
  });
  const filteredCount = plan.tasks.length - filteredTasks.length;
  if (filteredCount > 0) {
    console.log(`${logPrefix} (filtered ${filteredCount} terminal tasks)`);
  } else {
    console.log(logPrefix);
  }
  const filteredSet = new Set(filteredTasks);
  const rebuiltBatches = (plan.batches || []).map((batch) => batch.filter((taskId) => filteredSet.has(taskId))).filter((batch) => batch.length > 0);
  return buildBatchAwareQueue(filteredTasks, rebuiltBatches);
}
function printSummary(summary) {
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log("\uD83D\uDCCA Execution Summary");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log(`   Total tasks: ${summary.totalTasks}`);
  console.log(`   ✅ Passed: ${summary.passed}`);
  console.log(`   ❌ Failed: ${summary.failed}`);
  console.log(`   \uD83D\uDD04 Retries: ${summary.totalRetries}`);
  console.log(`   ⏱️  Duration: ${(summary.duration / 1000).toFixed(1)}s`);
  console.log("");
  if (summary.failed > 0) {
    console.log("❌ Failed tasks:");
    for (const [taskId, record] of summary.taskResults) {
      if (record.reviewVerdict?.result === "NOPASS" || record.devReport.status === "failed") {
        console.log(`   - ${taskId}: ${record.reviewVerdict?.reason || record.devReport.error || "Unknown error"}`);
      }
    }
    console.log("");
  }
  console.log("━".repeat(SEPARATOR_WIDTH));
  if (summary.failed === 0) {
    console.log("✅ All tasks executed successfully!");
  } else {
    console.log(`⚠️  Some tasks failed, check reports for details`);
  }
  console.log("");
  console.log("━".repeat(SEPARATOR_WIDTH));
  console.log("\uD83D\uDCCA Pipeline status saved to: .projmnt4claude/harness-status.json");
  console.log("\uD83D\uDCA1 Check progress: cat .projmnt4claude/harness-status.json");
  console.log("━".repeat(SEPARATOR_WIDTH));
}

// src/utils/path.ts
import * as path29 from "path";
import * as fs33 from "fs";
function getProjectDir5(cwd2 = process.cwd()) {
  return path29.join(cwd2, ".projmnt4claude");
}
function isInitialized2(cwd2 = process.cwd()) {
  const projectDir = getProjectDir5(cwd2);
  const configPath = path29.join(projectDir, "config.json");
  if (fs33.existsSync(configPath)) {
    return true;
  }
  const tasksDir = path29.join(projectDir, "tasks");
  if (fs33.existsSync(tasksDir)) {
    try {
      const taskDirs = fs33.readdirSync(tasksDir);
      return taskDirs.some((taskDir) => {
        const metaPath = path29.join(tasksDir, taskDir, "meta.json");
        return fs33.existsSync(metaPath);
      });
    } catch {
      return false;
    }
  }
  return false;
}

